+
+	cmd := &cobra.Command{
+		Use:   "lists",
+		Short: "List task lists",
+		Args:  cobra.NoArgs,
+		RunE: func(cmd *cobra.Command, _ []string) error {
+			u := ui.FromContext(cmd.Context())
+			account, err := requireAccount(flags)
+			if err != nil {
+				return err
+			}
+
+			svc, err := newTasksService(cmd.Context(), account)
+			if err != nil {
+				return err
+			}
